create table dirkspzm32.rep_sql_parameter (
    rep_id          number(*, 0) not null enable,
    param_id        number(*, 0) not null enable,
    param_name      varchar2(50 char) not null enable,
    param_typ       varchar2(3 char) default 'S' not null enable,
    param_info      varchar2(255 char),
    default_wert    varchar2(50 char),
    wert_maske      varchar2(20 char),
    order_index     number(*, 0) default 0 not null enable,
    dialog_abfrage  varchar2(1 char) default 'T' not null enable,
    auswahl_werte   varchar2(255 char),
    lookup_rep_name varchar2(100 char),
    dlg_input_check number(*, 5) default 0 not null enable,
    dlg_caption     varchar2(100 char),
    dlg_spalte_nr   number(*, 5) default 1 not null enable,
    dlg_gruppe_nr   number(*, 5) default 0 not null enable
);

alter table dirkspzm32.rep_sql_parameter
    add constraint pk_rep_sql_parameter primary key ( rep_id,
                                                      param_id )
        using index enable;

alter table dirkspzm32.rep_sql_parameter
    add constraint uix_sql_param_name unique ( param_name,
                                               rep_id )
        using index enable;


